% indices of all components of renewal part in kmrgd:
%ind_r_all = [];

delays = -[-par_tau];
if any(delays < 0)
    % the equation is advanced instead of delayed: we need to stop
    dydt = NaN(size(kmrgd));
    return
else
    tau_max = max(delays);
    if tau_max == 0
        % the equation is not delayed: we need to stop
        dydt = NaN(size(kmrgd));
        return
    end
end

